    <script>
        $(document).ready(function () {
            $('select.nice-select').niceSelect();

            $('#tourFilter').on('change', function () {
                const selected = $(this).val().toLowerCase();

                $('.gallery-item').each(function () {
                    const category = $(this).data('category').toLowerCase();
                    if (selected === 'all' || category === selected) {
                        $(this).closest('.col-lg-4, .col-md-6').show();
                    } else {
                        $(this).closest('.col-lg-4, .col-md-6').hide();
                    }
                });
            });


            $(document).ready(function () {
                $('.sub-menu .nav-link').on('click', function (e) {
                    e.preventDefault();
                    $('.sub-menu .nav-link').removeClass('active');
                    $(this).addClass('active');
                    $('.tab-content .tab-pane').removeClass('show active');
                    var target = $(this).attr('href');
                    $(target).addClass('show active');
                });
            });
        });

    </script>

